from typing import List, Dict, TextIOfrom .e_cov_reporttype import ECoverageReportTypefrom ..exceptions import (	FocalProjectNotSetError,	DataFileNotSetError,	ReportTypeNotSetError)class CoverageRcWriter:	"""		Rappresenta un oggetto in grado di scrivere files "coverage.rc" (di coverage.py)		in cui definisce le impostazioni di calcolo coverage che gli vengono specificate	"""		def __init__(self):		"""			Costruisce un nuovo CoverageRcWriter		"""		self._focal_dir: str = None		self._excl_paths: List[str] = None		self._datafile_path: str = "coverage.gtsai.data"		self._report_type: ECoverageReportType = ECoverageReportType.JSON		self._other_options: Dict[str, Dict[str, str]] = dict()					def set_focal_project(			self,			focal_dirname: str,			excluded: List[str] = None,	):		"""			Imposta il progetto focale di cui scrivere il "coverage.rc"						Parameters			----------				focal_dirname: str					Una stringa rappresentante la directory della Focal Project Root Path del progetto focale									excluded: List[str]					Opzionale. Default = `None`. Una lista di stringhe contenente le sotto-paths, relative alla					Full Project Root Path, da escludere nella valutazione della coverage								Raises			------				ValueError					Si verifica se:											- Il parametro `focal_root` ha valore `None` o è una stringa vuota						- Il parametro `excluded` è una lista vuota		"""		if (focal_dirname is None) or (focal_dirname == ""):			raise ValueError()		if excluded is not None:			if len(excluded) == 0 :				raise ValueError()		self._focal_dir = focal_dirname		self._excl_paths = excluded					def set_option(			self,	        section: str,			option: str,			value: str	):		"""			Imposta il valore di un opzione del coverage.rc che non sia "omit" oppure "source".			Se value ha valore `None` il precedente valore dell' opzione viene cancellato						Parameters			----------				section: str					Una stringa contenente il nome della sezione a cui appartiene l' opzione					che si sta impostando/cancellando									option: str					Una stringa contenente il nome dell' opzione che si vuole impostare/cancellare									value: str					Una stringa contenente il valore da impostare per l' opzione o la richiesta					di cancellazione tramite il valore `None`								Raises			------				ValueError					Si verifica se:						- Il parametro `section` ha valore `None` o è una stringa vuota						- Il parametro `option` ha valore `None` o è una stringa vuota						- Il parametro `option` ha valore "omit" oppure "source" (e `section` è "run" oppure "report")						- Il parametro `value` è una stringa vuota		"""		if (value == ""):			raise ValueError()		if (section is None) or (section == ""):			raise ValueError()		if ((option is None) or (option == "") or			((section in ["run", "report"]) and (option in ["omit", "source"]))):			raise ValueError()		if value is not None:			if self._other_options.get(section, None) is None:				self._other_options[section] = dict()			self._other_options[section][option] = value		else:			self._other_options[section].pop(option, None)							def write_rcfile(			self,			rcfile_path: str,	        use_relpaths: bool = True	):		"""			Scrive le impostazioni della coverage desiderate sul file "coverage.rc"			alla path specificata						Parameters			----------				rcfile_path: str					Una stringa rappresentante la path del file "coverage.rc" da creare									use_relpaths: bool					Opzionale. Default = `True`. Un booleano che indica se coverage.py deve					utilizzare paths relative per indicare i moduli di cui ha calcolato la coverage								Raises			------				ValueError					Si verifica se il parametro `rcfile_path` ha valore None									DataFileNotSetError					Si verifica se non è stato impostato							FocalProjectNotSetError					Si verifica se non è stato impostato alcun progetto focale prima di					chiamare quest' operazione									ReportTypeNotSetError					Si verifica se non è stato impostato alcuna tipologia di report che					coverage.py dovrà produrre prima di chiamare quest' operazione		"""		if rcfile_path is None:			raise ValueError()		if self._datafile_path is None:			raise DataFileNotSetError()		if self._focal_dir is None:			raise FocalProjectNotSetError()		if self._report_type is None:			raise ReportTypeNotSetError()				with open(rcfile_path, "w") as fpcovrc:			fpcovrc.write("[run]\n")			fpcovrc.write(f"source = {self._focal_dir}\n")			fpcovrc.write(f"data_file = {self._datafile_path}\n")			fpcovrc.write(f"relative_files = {use_relpaths}\n")			fpcovrc.write("\n")			self._write_omits(fpcovrc)			fpcovrc.write("\n")						if self._excl_paths is not None:				fpcovrc.write("[report]\n")				self._write_omits(fpcovrc)			sect_dict: Dict[str, str]						for section in self._other_options.keys():				sect_dict = self._other_options[section]				fpcovrc.write("\n")				fpcovrc.write(f"[{section}]\n")				for option in sect_dict.keys():					fpcovrc.write(f"{option} = {sect_dict[option]}\n")			fpcovrc.flush()							##	============================================================	##						PRIVATE METHODS	##	============================================================			def _write_omits(self, fp_covrc: TextIO):		"""			Scrive le paths escluse nel file coverage.rc che si sta creando.						Il `.flush()` non viene effettuato						Parameters			----------				fp_covrc: TextIO					Un puntatore a file, aperto in scrittura, rappresentante il file coverage.rc					che si sta creando		"""		if self._excl_paths is not None:			fp_covrc.write("omit = \n")			for excl_path in self._excl_paths:				fp_covrc.write(f"\t{excl_path}\n")